emails = re.findall(r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b', email_text)

for email in emails:
    if validate_email(email):
        name = email.split('@')[0]
        greeting = draft_greeting(name)
        print(f"Email: {email}, Greeting: {greeting}")

