    return length(split(trim(s), "\n"))
}
pure fn count_words(s: Text) -> Number {
    return length(split(lower(trim(s)), " "))
}
pure fn count_chars(s: Text) -> Number {
    return length(trim(s))
}
intent rate_conciseness(text: Text) -> Text {
    goal: concise_or_verbose
}
entry main(x: Text) {
    text = "The sun was setting. Birds flew home. Silence fell."
    return join([
        to_text(count_lines(text)), " lines, ",
        to_text(count_words(text)), " words, ",
        to_text(count_chars(text)), " characters; ",
        rate_conciseness(text)
    ], "")
}

