import json
import urllib.parse
import urllib.request

def parse_coords(s):
    return [(c, float(l)) for c, l in (p.split(':') for p in s.split(','))]

def sort_by_lat(pairs):
    return sorted(pairs, key=lambda x: x[1])

def describe_pattern(sorted_pairs):
    if not sorted_pairs:
        return "Empty input"
    first = sorted_pairs[0]
    last = sorted_pairs[-1]
    if first[1] < 0 and last[1] > 0:
        return "Bipolar pattern"
    elif all(l >= 0 for c, l in sorted_pairs):
        return "Northern hemisphere"
    else:
        return "Southern hemisphere"

def main():
    raw = 'Tokyo:35.6,London:51.5,Sydney:-33.8'
    pairs = parse_coords(raw)
    sorted_pairs = sort_by_lat(pairs)
    pattern = describe_pattern(sorted_pairs)
    print(pattern)

main()

