pure fn fibonacci(n: Number) -> Text {
    if n <= 1 { return join(["0"], "") }
    results = ["0", "1"]
    for i in range(2, n + 1) {
        next = to_text(to_number(results[i - 1]) + to_number(results[i - 2]))
        results = append(results, next)
    }
    return join(results, ", ")
}
pure fn golden_ratio_appears(sequence: Text) -> Boolean {
    parts = split(sequence, ", ")
    if length(parts) < 3 { return false }
    a = to_number(parts[length(parts) - 1])
    b = to_number(parts[length(parts) - 2])
    c = to_number(parts[length(parts) - 3])
    ratio = round(to_number(a) / to_number(b), 2)
    golden_ratio = round(to_number(b) / to_number(c), 2)
    return ratio == golden_ratio
}
entry main(x: Text) {
    fib_sequence = fibonacci(8)
    explanation = if golden_ratio_appears(fib_sequence) { "The golden ratio appears in this Fibonacci sequence." } else { "The golden ratio does not appear in this Fibonacci sequence." }
    return join([fib_sequence, " - ", explanation], "")
}

